previewCss:
.darma-loader-orbit-dots {
  position: relative;
  display: inline-block;
  width: 54px;
  height: 54px;
  color: #6366f1;
  animation: darma-loader-orbit-dots-spin 1.2s linear infinite;
}
.darma-loader-orbit-dots::before,
.darma-loader-orbit-dots::after {
  content: "";
  position: absolute;
  width: 14px;
  height: 14px;
  border-radius: 50%;
  background: currentColor;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
}
.darma-loader-orbit-dots::after {
  top: auto;
  bottom: 0;
  opacity: 0.35;
}
@keyframes darma-loader-orbit-dots-spin { to { transform: rotate(360deg); } }

